package com.corporativoalpha.bookingservice.services;import com.corporativoalpha.bookingservice.models.Booking;import com.corporativoalpha.bookingservice.models.Space;import com.corporativoalpha.bookingservice.models.User;import com.corporativoalpha.bookingservice.repositories.BookingRepository;import com.corporativoalpha.bookingservice.repositories.SpaceRepository;import com.corporativoalpha.bookingservice.repositories.UserRepository;import org.springframework.stereotype.Service;import java.time.LocalDate;import java.util.List;@Service public class BookingService {private final BookingRepository bookingRepository;private final SpaceRepository spaceRepository;private final UserRepository userRepository;public BookingService(BookingRepository bookingRepository, SpaceRepository spaceRepository, UserRepository userRepository){this.bookingRepository=bookingRepository;this.spaceRepository=spaceRepository;this.userRepository=userRepository;}public List<Booking> getMyBookings(Long userId){return bookingRepository.findByUserId(userId);}public Booking createBooking(Booking booking){if(booking.getBookingDate().isBefore(LocalDate.now())){throw new IllegalArgumentException("No se pueden realizar reservas en el pasado");}if(!booking.getEndTime().isAfter(booking.getStartTime())){throw new IllegalArgumentException("La hora de fin debe ser mayor a la hora de inicio");}Space space=spaceRepository.findById(booking.getSpace().getId()).orElseThrow(()->new RuntimeException("Espacio no encontrado"));if(booking.getAttendees() > space.getCapacity()){throw new IllegalArgumentException("La cantidad de asistentes excede la capacidad del espacio");}List<Booking> existingBookings=bookingRepository.findBySpaceIdAndBookingDate(space.getId(),booking.getBookingDate());for(Booking b:existingBookings){if(booking.getStartTime().isBefore(b.getEndTime()) && booking.getEndTime().isAfter(b.getStartTime())){throw new IllegalStateException("El espacio ya se encuentra reservado en ese rango horario");}}User user=userRepository.findById(booking.getUser().getId()).orElseThrow(()->new RuntimeException("Usuario no encontrado"));booking.setSpace(space);booking.setUser(user);return bookingRepository.save(booking);}public void cancelBooking(Long id){Booking booking=bookingRepository.findById(id).orElseThrow(()->new RuntimeException("Reserva no encontrada"));bookingRepository.delete(booking);}}
